/**
 * Deferred-Debt Marker Tracker — PostToolUse/Write hook
 *
 * The capture half of the deferred-debt feature (counterpart to the YAGNI
 * gate). When an agent takes a deliberate shortcut it drops an inline marker:
 *
 *   // ork-debt: <choice>, upgrade to <path>, when <trigger>
 *
 * After any Write/Edit/MultiEdit on a code file, this hook scans the file as
 * written and, if it contains debt markers, emits a non-blocking advisory
 * confirming the capture. The full ledger is surfaced at session start by the
 * instructions-loaded/debt-surfacer handler.
 *
 * Advisory only — never blocks. Opt out with ORK_DISABLE_DEBT_TRACKER=1.
 * See: src/skills/scope-appropriate-architecture/rules/deferred-debt-marker.md
 */

import { readFileSync } from 'node:fs';
import { isAbsolute, resolve, basename } from 'node:path';
import type { HookInput, HookResult, HookContext } from '../../types.js';
import { outputSilentSuccess, getField } from '../../lib/common.js';
import { NOOP_CTX } from '../../lib/context.js';
import { scanTextForDebt, formatDebtMarker, DEBT_SCAN_EXTENSIONS } from '../../lib/debt-markers.js';

const HOOK_NAME = 'posttool/write/debt-marker-tracker';

// File types whose comments can carry markers — derived from the shared
// DEBT_SCAN_EXTENSIONS so this never drifts from the surfacer's include list.
// Safe to build unescaped: the guard test pins every entry to /^[a-z0-9]+$/.
const CODE_EXT_RE = new RegExp(`\\.(${DEBT_SCAN_EXTENSIONS.join('|')})$`);

// Cap markers listed in a single advisory to avoid context bloat.
const MAX_LIST = 5;

export function debtMarkerTracker(input: HookInput, ctx: HookContext = NOOP_CTX): HookResult {
  if (process.env.ORK_DISABLE_DEBT_TRACKER === '1') return outputSilentSuccess();

  const toolName = input.tool_name || '';
  if (toolName !== 'Write' && toolName !== 'Edit' && toolName !== 'MultiEdit') {
    return outputSilentSuccess();
  }

  const filePath = getField<string>(input, 'tool_input.file_path') || '';
  if (!filePath || !CODE_EXT_RE.test(filePath)) return outputSilentSuccess();

  const abs = isAbsolute(filePath) ? filePath : resolve(ctx.projectDir, filePath);

  let text: string;
  try {
    text = readFileSync(abs, 'utf8');
  } catch {
    return outputSilentSuccess(); // silent: best-effort
  }

  const markers = scanTextForDebt(text);
  if (markers.length === 0) return outputSilentSuccess();

  ctx.log(HOOK_NAME, `Found ${markers.length} debt marker(s) in ${basename(filePath)}`);

  const shown = markers.slice(0, MAX_LIST).map(m => `  - ${formatDebtMarker(m)}`);
  const more = markers.length > MAX_LIST ? `\n  ...and ${markers.length - MAX_LIST} more` : '';
  const noTrigger = markers.some(m => !m.trigger)
    ? ' Tip: add ", when <trigger>" so the ledger can tell you when to revisit (without it, it is just a TODO).'
    : '';

  const message =
    `[debt-marker-tracker] Logged ${markers.length} deferred-debt marker(s) in ${basename(filePath)}:\n` +
    `${shown.join('\n')}${more}\n` +
    `Tracked in the deferred-debt ledger (surfaced at session start).${noTrigger}`;

  return {
    continue: true,
    hookSpecificOutput: {
      hookEventName: 'PostToolUse',
      additionalContext: message,
    },
  };
}

// Testing exports
export { CODE_EXT_RE, MAX_LIST };
